        for k, v in pairs(self._buildingSpriteList) do
            v:Destroy()
        end
        self._buildingSpriteList = {}
    end

    self._cameraMoveData = nil

    if self._effectPlayer then
        self._effectPlayer:Destroy()
        self._effectPlayer = nil
    end
    if self._effCtrl then
        self._effCtrl:Destroy()
    end

    if self._bubbleList then
        for k, v in pairs(self._bubbleList) do
            v:Destroy()
        end
        self._bubbleList = nil
    end

    if self._adCard then
        self._adCard:Destroy()
    end

    self:DestroyDreamBubble()
    self:DestroyBuildingNpc()

    self:StopXianshilibaoTimer()
    self:StopSwitchXianshilibaoTimer()
    self:StopShowKoreaNaverGameTimer()

    if self._xianshilibaoPlayer then
        self._xianshilibaoPlayer:Destroy()
        self._xianshilibaoPlayer = nil
    end

    self._eggPageDataList = {}

    self:DestroCityEnterBubble()

    if self.changeTimer1 then
        LxTimer.DelayTimeStop(self.changeTimer1)
        self.changeTimer1 = nil
    end

    if self.changeTimer2 then
        LxTimer.DelayTimeStop(self.changeTimer2)
        self.changeTimer2 = nil
    end

    -- self:ClearPlotGameEff()

    LMapBase.OnDestroy(self)
end

