function LCityMap:RefreshActivityAdRedPoint()
    local redPoint = "LayerRoot/BuildingLayer/Layer2/adcard/AdIcon/redPoint"
    if not self._mapTrans then return end

    local trans = CS.FindTrans(self._mapTrans, redPoint)
    if CS.IsNullObject(trans) then return end

    local adActivity = nil
    -- local dataList = gModelActivity:GetActivityDataByModelId(ModelActivity.MODEL_ACTIVITY_TYPE_112)
    local dataList = {}
    for i, v in ipairs(dataList) do
        local activityData = gModelActivity:GetActivityBySid(v.sid)
        local moreInfo = JSON.decode(activityData.moreInfo)
        local posterImg = moreInfo.posterImg
        if not string.isempty(posterImg) then
            adActivity = v
            break
        end
    end
    if not adActivity then return end

    local isRed = gModelRedPoint:GetActRedPointMap(adActivity.sid)
    CS.ShowObject(trans, isRed)
end
function LCityMap:ShowActivityAd()
    local adcardPath = "LayerRoot/BuildingLayer/Layer2/adcard/AdIcon"
    local trans = CS.FindTrans(self._mapTrans, adcardPath)
    if CS.IsNullObject(trans) then return end

    CS.ShowObject(trans, false)
    local adActivity = nil
    local iconStr = ""
    local pos = nil
    -- local dataList = gModelActivity:GetActivityDataByModelId(ModelActivity.MODEL_ACTIVITY_TYPE_112)
    local dataList = {}
    for i, v in ipairs(dataList) do
        local activityData = gModelActivity:GetActivityBySid(v.sid)
        local moreInfo = JSON.decode(activityData.moreInfo)
        local posterImg = moreInfo.posterImg
        local posterImgPos = moreInfo.posterImgPos
        if not string.isempty(posterImg) then
            adActivity = v
            iconStr = posterImg
            if not string.isempty(posterImgPos) then
                pos = LxDataHelper.ParseVector(posterImgPos)
            end
            break
        end
    end
    if not adActivity then return end

    self:SetSpriteRenderer(trans, iconStr)
    self:SetBuildClick(trans, function()
        gModelActivity:CommonActJump(adActivity.sid)
    end)
    CS.ShowObject(trans, true)
    if pos then
        trans.localPosition = pos
    end
end

function LCityMap:ShowBuildAd()
    if self._adCard then
        --self._adCard:InitAdCard()
        self._adCard:RefreshAdCard()
        return
    end
    local adcardPath = "LayerRoot/BuildingLayer/Layer2/adcard/BuildingAdCard"
    local trans = CS.FindTrans(self._mapTrans, adcardPath)
    if CS.IsNullObject(trans) then return end

    self._adCard = BuildingAdCard.New()
    self._adCard:CreateAdCard(self, trans)
    --self._adCard:InitAdCard()
    self._adCard:RefreshAdCard()
end

