function LCityMap:RefreshActivityNpc()
    --[[
    local oldSidNpcList = self._sidNpcList or {}
    local nexSidNpcList = {}
    local idleNpcNodes = {}
    local dataList = gModelActivity:GetActivityDataByModelId(ModelActivity.MODEL_ACTIVITY_TYPE_85)
    for i, v in ipairs(dataList) do
        if (v.status == ModelActivity.STATUS_INVALID and v.endTime > GetTimestamp()) or v.status == ModelActivity.STATUS_VALID then
            local activityData = gModelActivity:GetActivityBySid(v.sid)
            local moreInfo = JSON.decode(activityData.moreInfo)
            local dollSpine = moreInfo.dollSpine
            if not string.isempty(dollSpine) and not idleNpcNodes[dollSpine] then
                idleNpcNodes[dollSpine] = { path = "Layer2/adcard/TKK01", text = gModelActivity:GetLngNameById(moreInfo.dollSpineTxt) }
                nexSidNpcList[v.sid] = dollSpine
            end
        end
    end
    for i, v in pairs(oldSidNpcList) do
        if not nexSidNpcList[i] then
            local npc = self._npcList[v]
            if npc then
                npc:Destroy()
            end
        end
    end
    self._sidNpcList = nexSidNpcList
    self:ShowBuildingNpc(idleNpcNodes)
    ]]
end

function LCityMap:ShowBuildingNpc(idleNpcNodes)
    local npcList = self._npcList or {}
    self._npcList = npcList
    local layerBuildingTrans = CS.FindTrans(self._mapTrans, "LayerRoot/BuildingLayer")
    for k, v in pairs(idleNpcNodes) do
        if not npcList[k] then
            local trans = CS.FindTrans(layerBuildingTrans, v.path)
            local npc = LBuildingNpc:New()
            npcList[k] = npc
            local bodyData = {}
            bodyData.main = { 
                spine = k, dir = 2, aniScale = 1, bodyScale = 1, initAni = v.ani, showText = v.text, loadedFunc = v.loadedFunc,
                spineClick = function()
                    self:OnClickNpc(k)
                end, 
            }
            npc:CreateNpc(trans, k, bodyData, function(npcObj)
                self:OnClickBuildingNpcTalk(npcObj)
            end)
        end
    end
end

function LCityMap:ShowBuildingNpcTalk(npcKey, text, talkData, offset)
    local npcList = self._npcList or {}
    local npc = npcList[npcKey]
    if npc then
        if string.isempty(text) then
            npc:ShowTalk(nil, nil, nil)
        else
            npc:ShowTalk(text, talkData, offset)
        end
    end
end

function LCityMap:TryRefreshXianshilibaoNpc()
    self:StopXianshilibaoTimer()
    self._delayRefreshXianshilibaoTimer = LxTimer.DelayTimeCall(function()
        self._delayRefreshXianshilibaoTimer = nil
        self:RefreshXianshilibaoNpc()
    end, 1)
end

function LCityMap:TrySwitchXianshilibaoNpc()
    self:StopSwitchXianshilibaoTimer()

    if not self._nextXianshilibaoTime then return end

    local nexttime = self._nextXianshilibaoTime
    local nowTime = os.time()
    local distime = nexttime - nowTime
    if distime <= 0 then
        distime = 1
    end

    --到规定时间播放下一个
    self._switchXianshilibaoTimer = LxTimer.DelayTimeCall(function()
        self._switchXianshilibaoTimer = nil

        if not self._xianshilibaoPlayer then return end

        local oldData = self._xianshilibaoPlayer:GetCurrentGiftData()
        self._xianshilibaoPlayer:SwitchNextGiftData()
        local newData = self._xianshilibaoPlayer:GetCurrentGiftData()

        if oldData ~= nil and oldData == newData then return end

        if not self._bVisible then return end

        self:TryRefreshXianshilibaoNpc()
    end, distime)
end

function LCityMap:RefreshXianshilibaoNpc()
    self:StopXianshilibaoTimer()

    if self._npcList then
        local spineKey = "Mache"
        local curNpc = self._npcList[spineKey]
        if curNpc then
            curNpc:UpdateScale()
        end
    end

    if not self._xianshilibaoPlayer then return end

    self._xianshilibaoPlayer:RefreshGiftList()
    local currentGiftData = self._xianshilibaoPlayer:GetCurrentGiftData()

    --没有礼包数据了，直接删掉npc
    if not currentGiftData then
        self:StopSwitchXianshilibaoTimer()
        self:RemoveXianshilibaoNpc()
        return
    end

    self:CreateXianshilibaoNpc(currentGiftData)
end

function LCityMap:CreateXianshilibaoNpc(currentGiftData)
    self._isShowXianshilibao = true

    local npcList = self._npcList or {}
    self._npcList = npcList

    local spineKey = "Mache"
    local curNpc = npcList[spineKey]
    if curNpc then
        local nowData = curNpc:GetBodyGiftData()
        --相同分组不创建新的马车
        if nowData and nowData.ref.giftGroup == currentGiftData.ref.giftGroup then
            curNpc:SetBodyGiftData(currentGiftData)
            self:TrySwitchXianshilibaoNpc()
            return
        end

        self:RemoveXianshilibaoNpc()
    end

    --5分钟切换一次
    local nowTime = os.time()
    self._nextXianshilibaoTime = nowTime + (self._xianshilibaoDisTime or 0)
    self:TrySwitchXianshilibaoNpc()

    local spineRoot = "Layer2/xianshilibao/spine"
    local pathRoot = "Layer2/xianshilibao/path"
    local layerBuildingTrans = CS.FindTrans(self._mapTrans, "LayerRoot/BuildingLayer")
    local spineTrans = CS.FindTrans(layerBuildingTrans, spineRoot)
    local pathTrans = CS.FindTrans(layerBuildingTrans, pathRoot)

    local npc = LBuildingNpc:New()
    npcList[spineKey] = npc

    local bodyData = {}
    bodyData.main = { spine = spineKey, dir = 1, aniScale = 2, bodyScale = 1.4 }

    local giftData = currentGiftData
    local ref = gModelHero:GetShowEffectById(giftData.ref.showHero)
    if not string.isempty(ref.prefabName) then
        bodyData.subList = {}
        table.insert(bodyData.subList,{
            spine = ref.prefabName,
            dir = 2,
            aniScale = 0.8,
            bodyScale = 1,
            pos = Vector3.New(-1.085, -0.231, 0.01)
        })
    end
    npc:CreateNpc(spineTrans, spineKey, bodyData, function(npcObj)
        self:OnClickBuildingNpcTalk(npcObj)
    end, true)
    npc:CreateMovePath(pathTrans, 1)
    npc:SetBodyGiftData(giftData)

    local newNpcTrans = npc._npcTrans
    if newNpcTrans then
        self:SetBuildClick(newNpcTrans, function()
            self:OnClickXianshilibao(npc)
        end)
    end

    npc:MoveToIndex(4, function()
        -- 通知UI显示
        npc:ShowGiftUI(true)
    end)
end

function LCityMap:RemoveXianshilibaoNpc()
    self._isShowXianshilibao = false

    self:StopXianshilibaoTimer()

    local npcList = self._npcList or {}
    self._npcList = npcList
    local spineKey = "Mache"
    local npc = npcList[spineKey]
    if not npc then return end

    -- 通知UI隐藏
    npc:ShowGiftUI(nil, nil)

    npcList[spineKey] = nil

    local npcRemoveList = self._npcRemoveList or {}
    self._npcRemoveList = npcRemoveList
    table.insert(npcRemoveList, npc)

    --npc:SetBodyGiftData(nil)

    npc:MoveToEnd(function()
        npc:Destroy()
        table.removeidata(npcRemoveList, npc)
    end)
end

