function LCityMap:RefreshBuildingShow()
    if not CS.IsValidObject(self._mapTrans) then return end

    local layerBuildingTrans = CS.FindTrans(self._mapTrans, "LayerRoot/BuildingLayer")
    local rootName = self:GetMapName()
    local isUSARegion = gLGameLanguage:IsUSARegion()
    local isValid
    for k, v in pairs(self._buildingInfoList) do
        local path = v.name
        local tran = CS.FindTrans(layerBuildingTrans, path)
        if tran then
            local transPath = LxUiHelper.GetRelativePath(rootName, tran)
            local functionRefId = gModelFunctionOpen:GetRefIdByPath(transPath)
            local isForeign = v.isForeign
            isValid = isForeign == nil or (isForeign and isUSARegion)
            if isValid then
                if functionRefId then
                    local isShow = gModelFunctionOpen:CheckIsShow(functionRefId)
                    local lockTrans = CS.FindTrans(tran, "lock")
                    if isShow and v.checkFunc then
                        isShow = v.checkFunc()
                    end
                    --[[ 取消ios 提示屏蔽 20250303 以后根据新的发行进行
                    if lockTrans and PRODUCT_G_VER ~= 1 then
                    ]]
                    if lockTrans then
                        CS.ShowObject(lockTrans, not isShow)
                        LxUiHelper.SetSceneSpriteGray(tran, not isShow)
                        local sprite = LxUiHelper.FindSceneSprite(tran)
                        if sprite then
                            sprite.color = isShow and Color.white or Color.New(0.78, 0.78, 0.78, 1)
                        end
                    else
                        if functionRefId == 36000001 then
                            local isOpen = gModelFunctionOpen:CheckIsOpened(functionRefId)
                            CS.ShowObject(tran, isOpen)
                        else
                            CS.ShowObject(tran, isShow)
                        end
                    end
                end
            else
                CS.ShowObject(tran, false)
            end
        end
    end

    self:RefreshBuildingNpc()
    self:RefreshActivityNpc()
    self._limitCallSid = nil
    self._limitActivityData = nil
    self:CheckShowLimitCallHot()
end

