function LCityMap:GetMapCityOffsetY()
    local offset = -1.32
    if self._parentScene then
        local adaptOffset = self._parentScene:GetCameraAdaptOffset()
        adaptOffset = adaptOffset and adaptOffset or 0
        offset = offset + adaptOffset
    end
    return offset
end

function LCityMap:MoveToPosWithAdjustY(pos, time, func)
    if not self._cti2DCameraCtrl then return end

    local offset = -1.32
    if self._parentScene then
        local adaptOffset = self._parentScene:GetCameraAdaptOffset()
        adaptOffset = adaptOffset and adaptOffset or 0
        offset = offset + adaptOffset
    end
    pos.y = offset
    -- 2025-6-23 目前地图为固定不可划，offset设置的参数为其它项目参数，不准确
    pos.x = 0
    pos.y = 0
    pos.z = 0
    self._cti2DCameraCtrl:MoveTo(pos, time, func, true)
end

