    if not CS.IsValidObject(self._mapTrans) then return end

    --[[
    local mapTheme = gLGameDisplayTheme:GetMapTheme()
    local spineList = self._spineList or {}
    local refs = gModelDreamFountain:GetDreamFountainPosShowRef(mapTheme)
    local layerBuildingTrans = CS.FindTrans(self._mapTrans, "LayerRoot/BuildingLayer")
