function LCityMap:DreamFountainPlayAnimation()
    if not self._spineList then return end
    --local _typeState = gModelDreamFountain:GetAnimState()
    --if not _typeState then
    if true then return end

    self._dreamEffectMap = self._dreamEffectMap or {}
    --[[
    local mapTheme = gLGameDisplayTheme:GetMapTheme()
    local infoList = gModelDreamFountain:GetFountainInfoList()
    for i, v in pairs(infoList) do
        local dp = self._spineList[v.type]
        if dp then
            local state = _typeState[v.type]
            local posRef = gModelDreamFountain:GetDreamFountainPosShowRefByRefId(v.type, mapTheme)
            local stateAnim = string.split(posRef.stateAnim, "|")
            local stateAnimEff = string.split(posRef.stateAnimEff, "|")
            local anim = stateAnim[state]
            local eff = stateAnimEff[state]
            if anim then
                local animArr = string.split(anim, "=")
                --dp:SetAlpha(1)
                dp:PlayAnimation(0, animArr[2], true)
            end
            local effObj = self._dreamEffectMap[posRef.type]
            if effObj then
                effObj:Destroy()
            end
            if eff then
                local effArr = string.split(eff, "=")
                local effectName = effArr[2]
                if not string.isempty(effectName) then
                    effObj = LDisplayEffect:New()
                    effObj:CreateEffect(dp:GetParentTrans(), effectName)
                    effObj:SetLoadedFunction(function()

                    end)
                    effObj:StartLoadEffect()
                    self._dreamEffectMap[posRef.type] = effObj
                end
            end
        end
    end
    --]]
end

