function LCityMap:IsTouchMoving()
    if not self._cti2DCameraCtrl then return false end

    local bInertiaMoving = self._cti2DCameraCtrl:IsInertiaMoving()
    local bTouchMoving = self._cti2DCameraCtrl:IsTouchMoving()
    return bInertiaMoving or bTouchMoving
end
function LCityMap:MoveCamera(pos, endCall, time, isGuide)
    if not self._isGuideReady then return false end
    if not isGuide and self._isGuiding then return end

    self._isGuiding = isGuide
    local func = function()
        self._isGuiding = false
        self._cameraMoveData = nil
        if endCall then
            endCall()
        end
    end
    self._cameraMoveData = { pos = pos, func = endCall }
    time = time or 0.5
    self:MoveToPosWithAdjustY(pos, time, func)
    return true
end

function LCityMap:OnSetClick(bool)
    local layerBuildingTrans = CS.FindTrans(self._mapTrans, "LayerRoot/BuildingLayer")
    local buildingInfoList = self._buildingInfoList
    local len = #buildingInfoList
    for i = 1, len do
        local buildingInfo = buildingInfoList[i]
        local btn = CS.FindTrans(layerBuildingTrans, buildingInfo.name)
        if btn then
            if bool then
                local func = buildingInfo.func
                if func ~= nil then
                    self:SetBuildClick(btn, func)
                end
            else
                self:SetBuildClick(btn, function()
                    GF.ShowMessage(ccClientText(19662))
                end)
            end
        end
    end
end

function LCityMap:OnPrepareEnterMap()
    if LOG_INFO_ENABLED then
        printInfoNR("========== OnPrepareEnterMap")
    end

    --if self._cti2DCameraCtrl then
    --	self._cti2DCameraCtrl:EnableTouchMove(true)
    --end

    --if self._effectTuoweiRoot then
    --	for _,v in ipairs(self._effectTuoweiRoot) do
    --		CS.ShowObject(v, true)
    --	end
    --end

    self:SetIsOnClick()

    self._effectTuoweiRoot = {}
    self._effectRoot = {}
    self._chengRoot = nil

    local layerEffectTrans = CS.FindTrans(self._mapTrans, "LayerRoot")
    if layerEffectTrans then
        --需要特殊控制播放的节点信息记录
        self._chengRoot = CS.FindTrans(layerEffectTrans, "EffectLayer/chengnei")
        local effectList = self._effList
        for i = 1, #effectList do
            self._effectRoot[i] = CS.FindTrans(layerEffectTrans, "huidie" .. i)
        end
    end

    local LMapEffectPlayer = LxRequire("LApp.Scene.Object.LMapEffectPlayer")
    if LMapEffectPlayer then
        if self._effectPlayer then
            self._effectPlayer:Destroy()
        end
        self._effectPlayer = LMapEffectPlayer:New()
        self._effectPlayer:Init(self._chengRoot, self._effectRoot, self._chengneiEffectList, self._effList)
    end

    local LXianshilibaoPlayer = LxRequire("LApp.Scene.Object.LXianshilibaoPlayer")
    if LXianshilibaoPlayer then
        if self._xianshilibaoPlayer then
            self._xianshilibaoPlayer:Destroy()
        end
        self._xianshilibaoPlayer = LXianshilibaoPlayer:New()
    end


end

