function LCityMap:OnEnterMap()
    self:InitMapEvent()
    self:InitBuildingAdCard()
    self:RefreshBuildingShow()
    --self:RefreshEnterBuildingBubbleLock()
    self:InitBuildingList()
    --self:RefreshXianshilibaoNpc()
    --GF.CloseWndByName("UIMinFight")

    if self._effectTuoweiRoot then
        for _, v in ipairs(self._effectTuoweiRoot) do
            CS.ShowObject(v, true)
        end
    end

    self:InitCameraCtrlMovePos()

    gModelGeneral:SetHasEnteredCityMap()

    FireEvent(EventNames.CHECK_SHOW_TASK_FINISH)

    local wnd = GF.FindFirstWndByName("UIMCity")
    if not wnd then
        GF.OpenWnd('UIMCity')
    end

    GF.OpenWndTop("UISayFlow")

    -- self:RefreshPlotGameEff()

    if self._effectPlayer then
        self._effectPlayer:RestartPlay()
    end

    self:RefreshAllBubble()

    self:SetDreamFountainSpine()

    self:OnSimulateAdmireChange()

    self:ChangeMapSkin(false)

    --gModelGeneral:CheckSendStoryFinish()
    FireEvent(EventNames.FIRST_ENTER_CITY)

    -- gModelGuide:CheckShowSDkGameGuide()

    local wndMap = {
        ["UICartront"] = true,
        ["UIBlockBlack"] = true,
        ["UILoadsng"] = true

    }

    if not self._bCheckShowNaver then
        self:ShowKoreaNaverGame()
    end

    if gLGameUI:IsExistOneWnd(wndMap) then
        return
    end

    gModelWndPop:CheckPopWnd()

    --gModelGeneral:CheckShowIgnoredPopGift()

    self:ResetCameraPos(0)
    self:MoveCamera(Vector3.zero, nil, 0)
end

function LCityMap:InitCameraCtrlMovePos()
    if not self._cti2DCameraCtrl then return end

    --self._cti2DCameraCtrl:EnableTouchMove(true)
    local camerax = -4.83
    if self._cameraPosX then
        camerax = self._cameraPosX
        self._cameraPosX = nil
    end
    local pos = Vector3.New(camerax, self:GetMapCityOffsetY(), 0)
    local endCall = nil
    if self._guideData then
        pos = self._guideData.pos
        endCall = self._guideData.endCall
    end
    self._guideData = nil
    self:MoveCamera(pos, endCall, 0)
end
