function LCityMap:ShowKoreaNaverGame()
    if LGameSettings.platformRegion ~= LRegionConst.KOREA then
        self._bCheckShowNaver = true
        return
    end
    self:StopShowKoreaNaverGameTimer()
    self._delayShowKoreaNaverGameTimer = LxTimer.DelayTimeCall(function()
        if gModelGuide:HasWaitGuide() or gModelGuide:IsInGuide() then return end

        self._bCheckShowNaver = true
        gLSdkImpl:CallMethod(LSdkMethod.CallSdkNaverGame, "0")
    end, 0.5, true)
end

function LCityMap:StopShowKoreaNaverGameTimer()
    if self._delayShowKoreaNaverGameTimer then
        LxTimer.DelayTimeStop(self._delayShowKoreaNaverGameTimer)
        self._delayShowKoreaNaverGameTimer = nil
    end
end

