function LCityMap:OnCameraAdapt()
    LMapBase.OnCameraAdapt(self)

    if not self._cti2DCameraCtrl then return end

    if self._cameraMoveData then
        self:MoveCamera(self._cameraMoveData.pos, self._cameraMoveData.func, 0, true)
    else
        local cameraPos = self._cti2DCameraCtrl.CameraPos
        self:MoveCamera(Vector3(cameraPos.x, 0, 0), nil, 0, true)
    end
end

