function LCityMap:OnClickShiLianTa()
    local combatTypes = {
        LCombatTypeConst.COMBAT_TOWER_BATTLE,
        LCombatTypeConst.COMBAT_TOWER_WATER,
        LCombatTypeConst.COMBAT_TOWER_FIRE,
        LCombatTypeConst.COMBAT_TOWER_WIND,
        LCombatTypeConst.COMBAT_TOWER_LIGHT_DARK,
        LCombatTypeConst.COMBAT_TYPE_75,
    }

    local isFight = false
    local combatType = nil
    for k, v in pairs(combatTypes) do
        isFight = gLFightManager:IsCombatTypeInFight(v)
        if isFight then
            combatType = v
            break
        end
    end

    if isFight then
        gLFightManager:PrepareGoToBattle(combatType, {})
    else
        if gModelTower:GetIsUnlockRaceTower() then
            GF.OpenWndBottom("UITaRacePop")
        else
            GF.OpenWndBottom("UITaWin")
        end
    end
end

