function LCityMap:OnClickXianshilibao(npcObject)
    --local npcList = self._npcList or {}
    --local spineKey = "Mache"
    --local npc = npcList[spineKey]
    --if not npc then
    --	GF.ShowMessage(ccClientText(13423))
    --	return
    --end
    local npc = npcObject
    if not npc then return end

    local giftData = npc:GetBodyGiftData()
    if not giftData then return end

    local dataList = gModelPopupGift:GetGiftList()
    if not dataList or not dataList[giftData.id] then
        GF.ShowMessage(ccClientText(13423))
        return
    end

    local id = giftData.id or 1
    local list, index = gModelPopupGift:GetPopGiftShowList(id)
    local gift = list[1]
    local giftType = 0
    if gift and gift.ref and gift.ref.giftType == 1 then
        giftType = 1
    end
    local giftWndName = giftType == 0 and "UIPop2Gift" or "UIPop4Gift"
    GF.OpenWnd(giftWndName, { id = id, dataList = list, index = index })
    -- ThinkingData
    local attr1 = gModelPopupGift:FormatPopGiftStr(giftData, index)
    gLxTKData:OnTAClientEventReq(LxTKData.CLIENT_POPUP_GIFT, "popup_click", attr1)
end

function LCityMap:OnClickBuildingNpcTalk(npcObj)
    local npcKey = npcObj:GetNpcKey()
    local talkData = npcObj:GetTalkData()

    if "Huochainv" == npcKey then
        --加入判断点击跳转梦境秘闻的功能
        if self._showAnnieDreamSecret then
            self:OnClickDreamSecret()
            return
        end

        gModelShop:SetGoodsBubbleClicked()
        gModelFunctionOpen:Jump(talkData.jumpId, nil, nil, { isFromBubble = true, goodsId = talkData.goodsId })
    elseif "Kongjudaocao" == npcKey then
        self:OnClickDreamSecret()
    elseif "Mache" == npcKey then
        self:OnClickXianshilibao(npcObj)
    else
        self:OnClickNpc(npcKey)
    end
end
function LCityMap:OnClickNpc(npcKey)
    local dataList = gModelActivity:GetActivityDataByModelId(ModelActivity.MODEL_ACTIVITY_TYPE_85)
    for i, v in ipairs(dataList) do
        local activityDataW = gModelActivity:GetWebActivityDataById(v.sid)
        if activityDataW and activityDataW.config then
            local dollSpine = activityDataW.config.dollSpine
            if not string.isempty(dollSpine) then
                if dollSpine == npcKey then
                    gModelActivity:CommonActJump(v.sid)
                end
            end
        end
    end
end

