function LCityMap:ShowAnnieDreamSecretTipsBubble(show)
    if not gModelPlayerSpace:GetIsMe() then return end

    if not show then
        self:HideAnnieDreamSecretTipsBubble()
        return
    end

    local sid = self._annieDreamSecretSid
    if not sid then
        self:HideAnnieDreamSecretTipsBubble()
        return
    end

    local actData = gModelActivity:GetActivityBySid(sid)
    local moreInfo = JSON.decode(actData.moreInfo)
    local close_entry = moreInfo.close_entry or {}
    local isHideList = {}
    for k, v in pairs(close_entry) do
        isHideList[v] = true
    end

    local page = gModelActivity:GetWebActivityPageData(sid, 1)
    local maxEntryId
    if page then
        for k, v in pairs(page.entries) do
            local entryId = v.id
            if not isHideList[entryId] then
                if not maxEntryId or maxEntryId < entryId then
                    maxEntryId = entryId
                end
            end
        end
    end

    if not maxEntryId then
        printInfoN2("配置缺失", string.format("活动模板34， sid=%s，分页数据为空", sid))
        self:HideAnnieDreamSecretTipsBubble()
        return
    end

    local ref = gModelActivity:GetWebActivityEntryData(sid, 1, maxEntryId)
    if not ref then
        printInfoN2("配置数据缺失", string.format("活动模板34，sid=%s，分页数据id=%s为空", sid, maxEntryId))
        self:HideAnnieDreamSecretTipsBubble()
        return
    end

    self._showAnnieDreamSecret = true
    local text = ref.title1
    self:ShowBuildingNpcTalk("Huochainv", text)
end

function LCityMap:HideAnnieDreamSecretTipsBubble()
    self._showAnnieDreamSecret = false
    if table.isempty(self._goodsBubbleData) then
        self:ShowBuildingNpcTalk("Huochainv", nil, nil)
    else
        local show = self._goodsBubbleData.show
        local bubbleData = self._goodsBubbleData.bubbleData
        self:ShowGoodsBubble(show, bubbleData)
        self._goodsBubbleData = nil
    end
end

