function LCityMap:InitBuildingList()
    self._buildingLayer = {}
    self._buildingList = {}
    if not self._mapTrans then
        --printInfoN2("cjh---", "mapTrans 为空")
    else
        table.insert(self._buildingLayer, CS.FindTrans(self._mapTrans, "LayerRoot/BuildingLayer/Layer0"))
        table.insert(self._buildingLayer, CS.FindTrans(self._mapTrans, "LayerRoot/BuildingLayer/Layer1"))
        table.insert(self._buildingLayer, CS.FindTrans(self._mapTrans, "LayerRoot/BuildingLayer/Layer2"))
    end

    for k, layer in ipairs(self._buildingLayer) do
        if layer then
            local num = layer.childCount
            for i = 1, num do
                local tran = layer:GetChild(i - 1)
                table.insert(self._buildingList, tran)
            end
        end
    end
    self:CreateCityEnterBubble()
end

--创建入口bubble
function LCityMap:CreateCityEnterBubble()
    self:DestroCityEnterBubble()
    self._buildingEnterBubbles = {}
    -- 红点要和气泡一个层级 这里使用tranname 作为key 持有对应的应用
    self._buildingLocks = {}

    for k, tran in ipairs(self._buildingList) do

        --local itemdata = {
        --    followTran =tran,
        --    offset = Vector3(0, 0, 0),
        --    text = "noname",
        --}
        if tran.gameObject.activeSelf then
            --printInfoN2("cjh---", "这个控件是激活状态" .. tran.name)
            local transName = tran.name
            local enterBubble = LMainCityEnterBubble:New()
            enterBubble:CreateBubble("CityEnterBubble", transName, self._checkLockFunctionId[transName])
            enterBubble:SetBuildingTrans(tran, Vector3(0, 0, 0))
            table.insert(self._buildingEnterBubbles, enterBubble)
            self._buildingLocks[transName] = enterBubble
        end
    end
    self:TimerStop(self._createEnterTimeKey)
    self:TimerStart(self._createEnterTimeKey, 1, true, -1)

    --printInfoN2("cjh---", "INIT --- create bubble  --- OK ")

end

--bubble的锁
function LCityMap:RefreshEnterBuildingBubbleLock()
    if self._buildingLocks then
        for k, v in pairs(self._buildingLocks) do
            v:UpdateLockState()
        end
    end
end

--销毁入口bubble
function LCityMap:DestroCityEnterBubble()
    self:TimerStop(self._createEnterTimeKey)
    if self._buildingEnterBubbles then
        for k, bubble in ipairs(self._buildingEnterBubbles) do
            if bubble then
                bubble:DestroyBubble()
            end
        end
        self._buildingEnterBubbles = nil
        self._buildingRedpoints = nil
    end
end

function LCityMap:GetBubbleByType(type, prefabName)
    if not self._bubbleList then
        self._bubbleList = {}
    end

    local bubble = self._bubbleList[type]
    if bubble then return bubble end

    if type == LCityMap.GOOD_BUBBLE then
        bubble = LGoodsBubble:New()
        -- elseif type == LCityMap.TREASURE_BUBBLE then
        --     bubble = LTreasureBubbleEx:New()
        -- elseif type == LCityMap.SECRET_BUBBLE then
        --     bubble = LSecretBubble:New()
        -- elseif type == LCityMap.DREAM_BUBBLE then
        --     bubble = LTreasureBubble:New()
    elseif type == LCityMap.SERVER_TIME_BUBBLE then
        bubble = LSecretBubble:New(prefabName)
    elseif type == LCityMap.LIMIT_CALL_BUBBLE then
        bubble = LActLimitCallBubble:New()
    end

    self._bubbleList[type] = bubble
    return bubble
end

function LCityMap:DestroyBubbleByType(type)
    if not self._bubbleList then return end

    local bubble = self._bubbleList[type]
    if bubble then
        bubble:Destroy()
    end
    self._bubbleList[type] = nil
end

