function LCityMap:RefreshServerTimeBubble()
    local bubble = self:GetBubbleByType(LCityMap.SERVER_TIME_BUBBLE)
    if not bubble then return end

    local text = self:GetCurTimeStr()
    bubble:RefreshText(text)
end

function LCityMap:GetCurTimeStr()
    local date = LUtil.OSDate("*t", GetTimestamp())
    return string.replace(ccClientText(1002), date.year, date.month, date.day, fixedTimeToTwo(date.hour), fixedTimeToTwo(date.min))
end

function LCityMap:GetLimitCallTimerStr()
    local limitActivityData = self._limitActivityData
    if not limitActivityData then
        self:TimerStop(self._limitCallTimerKey)
        self:HideLimitCallBubble()
        self._limitCallSid = nil
        self._limitActivityData = nil
        return ""
    end
    local curTime = GetTimestamp()
    local endTime = tonumber(limitActivityData.endTime)
    local lastNum = endTime - curTime
    if lastNum <= 0 then
        self:TimerStop(self._limitCallTimerKey)
        self:HideLimitCallBubble()
        self._limitCallSid = nil
        self._limitActivityData = nil
        return ""
    end
    return LUtil.FormatTimespanCn(lastNum)
end

function LCityMap:RefreshLimitCallTimerStr()
    local bubble = self:GetBubbleByType(LCityMap.LIMIT_CALL_BUBBLE)
    if not bubble then return end

    local timeStr = self:GetLimitCallTimerStr()
    bubble:SetTimeTxt(timeStr)
end

function LCityMap:CheckEnterIsOk()
    for k, v in ipairs(self._buildingEnterBubbles) do
        if not v or not v:GetCurRedPoint() then
            printInfoN2("cjh---------", "createEnter---Loading")
            return
        end
    end

    self:TimerStop(self._createEnterTimeKey)
    self:RegisterRedPoint()
    self:RefreshAllRedPoint()
    self:RefreshEnterBuildingBubbleLock()
end

function LCityMap:OnTimer(key)
    if self._serverTimeKey == key then
        self:RefreshServerTimeBubble()
    elseif self._eggTimerKey == key then
        self:OnEggTimeFunc()
    elseif self._eggClickClearTimerKey == key then
        self:ClearEggClickList()
    elseif self._limitCallTimerKey == key then
        self:RefreshLimitCallTimerStr()
    elseif self._createEnterTimeKey == key then
        self:CheckEnterIsOk()
    end
end

