function LCityMap:CreateShareNpc(sid)
    if self._shareActId ~= sid then return end

    local webData = gModelActivity:GetWebActivityDataById(sid)
    if not webData then return end

    local npcList = self:GetNpcList()
    local npc = npcList["ShareNpc"]
    if npc then return end

    local root = self:GetNpcRoot()
    npc = LBuildingNpc:New()
    npcList["ShareNpc"] = npc

    local spine = "Feicuifashi"
    local bodyData = {}
    bodyData.main = {
        spine = spine,
        dir = 2,
        aniScale = 1,
        bodyScale = 0.7,
        initAni = "idle",
        pos = Vector3.New(-4.04, -1.67, 0),
        isFixScale = true,
        spineClick = function()
            self:OnClickShareNpc(sid)
        end
    }
    npc:CreateNpc(root, spine, bodyData, function(...)
        self:OnClickShareNpc(sid)
    end)
    local str = webData.config.showSpineText
    npc:ShowTalk(str, nil, Vector3.New(0, 0.8, 0))
end

function LCityMap:HideLimitCallBubble()
    local bubble = self:GetBubbleByType(LCityMap.LIMIT_CALL_BUBBLE)
    if bubble then
        bubble:SetVisible(false)
    end

    self._limitCallSid = nil
    self._limitActivityData = nil
end

function LCityMap:CheckShowLimitCallHot()
    local show, sid = gModelActivity:CheckShowLimitCall()
    if not self._isOnClick then
        show = false
    end

    if show then
        if not self._limitCallSid then
            self._limitActivityData = nil
            self._limitCallSid = sid
            gModelActivity:ReqActivityConfigData(sid)
        end
    else
        self:HideLimitCallBubble()
    end
end

function LCityMap:CreateLimitCallBubble(sid)
    if self._limitCallSid ~= sid then return end

    local oldData = self._limitActivityData
    if oldData then
        local curTime = GetTimestamp()
        local endTime = tonumber(oldData.endTime)
        if endTime - curTime > 0 then
            self:TimerStop(self._limitCallTimerKey)
            self:HideLimitCallBubble()
            return
        end
    end

    self:TimerStop(self._limitCallTimerKey)
    self._limitActivityData = nil
    local activityData = gModelActivity:GetActivityBySid(sid)
    if not activityData then
        self._limitCallSid = nil
        self:HideLimitCallBubble()
        return
    end

    if activityData.status == 3 then
        self._limitCallSid = nil
        self:HideLimitCallBubble()
        return
    end

    local bubble = self:GetBubbleByType(LCityMap.LIMIT_CALL_BUBBLE)
    if not bubble then return end

    local BubbleRootTrans = self._BubbleRootTrans
    if not BubbleRootTrans then
        local zhaohuanTrans = CS.FindTrans(self._mapTrans, "LayerRoot/BuildingLayer/Layer1/zhaohuan")
        if not zhaohuanTrans then return end

        BubbleRootTrans = CS.NewObject("BubbleRoot", zhaohuanTrans)
        if not BubbleRootTrans then return end

        BubbleRootTrans.localPosition = Vector3.zero
    end

    if not BubbleRootTrans then return end

    self._limitActivityData = activityData
    bubble:CreateBubble({
        followTran = BubbleRootTrans,
        offset = Vector3(0, -0.5, 0),
        effName = "ui_fx_huoyantubiao",
        limitStr = ccClientText(32108),
        timeStr = self:GetLimitCallTimerStr(),
    })
    bubble:SetVisible(true)
    self:TimerStart(self._limitCallTimerKey, 1, false, -1)
end

