function LCityMap:CheckShowLimitTimeCorridor()
    local show, sid = gModelActivity:CheckCityTimeCorridorShow()
    if not self._isOnClick then
        show = false
    end
    if show then
        self._limitTimeCorridorSid = sid
        local webData = gModelActivity:GetWebActivityDataById(sid)
        if webData then
            self:CreateLimitTimeCorridorSpine(sid)
        else
            gModelActivity:ReqActivityConfigData(sid)
        end
    else
        local spineKey = self._limitTimeCorridorSpineKey
        local npcList = self:GetNpcList()
        local npc = npcList[spineKey]
        if npc then
            npc:Destroy()
            npcList[spineKey] = nil
        end
    end
end

function LCityMap:CreateLimitTimeCorridorSpine(sid)
    if self._limitTimeCorridorSid ~= sid then return end

    local webData = gModelActivity:GetWebActivityDataById(sid)
    if not webData then return end

    local activityData = gModelActivity:GetActivityBySid(sid)
    if not activityData then return end

    local config = webData.config
    local spine = config.spine
    local txt = config.txt
    local endTime = activityData.endTime or 0

    local actTrans = "LayerRoot/BuildingLayer/Layer1/actlimittimecorridor"
    local trans = CS.FindTrans(self._mapTrans, actTrans)
    if CS.IsNullObject(trans) then return end

    local spineKye = self._limitTimeCorridorSpineKey
    local npcList = self:GetNpcList()
    local npc = npcList[spineKye]
    if npc then return end

    local root = trans--self:GetNpcRoot()
    npc = LBuildingNpc:New()
    npcList[spineKye] = npc

    local bodyData = {}
    bodyData.main = {
        spine = spine,
        dir = 2,
        aniScale = 1,
        bodyScale = 1,
        initAni = "idle",
        pos = Vector3.New(0, 0, 0),
        isFixScale = true,
        spineClick = function()
            self:OnClickLimitTimeCorridor(sid)
        end
    }
    npc:CreateNpc(root, spine, bodyData, function(...)
        self:OnClickLimitTimeCorridor(sid)
    end)

    local str = string.gsub(txt, "\\n", "\n")
    npc:ShowTalk(str, nil, Vector3.New(0.55, 1.3, 0), "Bubble3")
    npc:SetBodyTimeData({
        endTime = endTime * 1000,
        setTimeCn = true,
    })
    npc:ShowTimeUI(true, Vector3.New(0, -0.4, 0))

    local redPoint = CS.FindTrans(trans, "redPoint")
    CS.ShowObject(redPoint, false)
end

