function LCityMap:ShowPaintedEgg(sid)
    local actData = gModelActivity:GetActivityBySid(sid)
    local moreInfo = JSON.decode(actData.moreInfo)
    local nowEggs = moreInfo.nowEggs
    local eggRefList = {}
    local key
    for k, v in ipairs(nowEggs) do
        eggRefList[v] = true
    end

    local spriteList = self:GetBuildingSpriteList()
    for k, v in pairs(spriteList) do
        if string.find(k, self._paintedEggKey) then
            key = string.gsub(k, self._paintedEggKey, "")
            key = tonumber(key)
            if not eggRefList[key] then
                self:ClearSpriteListByKey(k)
            end
        end
    end

    for k, v in pairs(eggRefList) do
        key = self._paintedEggKey .. k
        if not spriteList[key] then
            self:CreatePaintedEggNpc(k)
        end
    end

    self:TimerStop(self._eggTimerKey)
    --0=未到大奖领取条件， 1=大奖可领取，2=所有彩蛋，大奖均已领取
    local hasCollNumReward = moreInfo.hasCollNumReward

    if hasCollNumReward == 0 then
        self._hasCollNumReward = moreInfo.hasCollNumReward
        self._nextPaintedEggTime = moreInfo.nextRefreshTime / 1000

        local activityWedData = gModelActivity:GetWebActivityDataById(sid)
        if not activityWedData then return end

        local config = activityWedData.config
        self._maxEggNum = config.egg or GameTable.CityMapConfRef["egg"]
        self:TimerStart(self._eggTimerKey, 1, true, -1)
    elseif hasCollNumReward == 1 and table.isempty(eggRefList) and not gModelWndPop:CheckHadWnd("UIPggPop") then
        if GF.FindFirstWndByName("UIAward") then
            self._paintedEggWaitShowPop = true
        else
            self:ShowEggCollNumRewardPop()
        end
    end
end

