function LCityMap:ClearEggList()
    local spriteList = self:GetBuildingSpriteList()
    local key = self._paintedEggKey
    for k, v in pairs(spriteList) do
        if string.find(k, key) then
            v:Destroy()
        end
        spriteList[k] = nil
    end
end

function LCityMap:AddEggClickNum(refId)
    local oldNum = self._eggClickList[refId] or 0
    self._eggClickList[refId] = oldNum + 1
end

function LCityMap:GetEggClickNum(refId)
    return self._eggClickList[refId] or 0
end

function LCityMap:ClearEggClickList()
    self._eggClickList = {}
end

function LCityMap:OnEggTimeFunc()
    local nextTime = self._nextPaintedEggTime
    if nextTime and nextTime > GetTimestamp() then return end

    self:TimerStop(self._eggTimerKey)
    local spriteList = self:GetBuildingSpriteList()
    local key = self._paintedEggKey
    local nowEggNum = 0
    for k, v in pairs(spriteList) do
        if string.find(k, key) then
            nowEggNum = nowEggNum + 1
        end
    end

    if self._hasCollNumReward == 0 and self._paintedEggActSidId and nowEggNum < self._maxEggNum then
        --刷新主城上彩蛋信息
        gModelActivity:OnActivitySpecialOpReq(self._paintedEggActSidId, 0, 0, nil, "3_0", ModelActivity.EGG_REWARD)
    end
end

function LCityMap:CheckShowAnnieDreamSecret()
    local show, positionList = gModelActivity:HasActivitySix()
    if not self._isOnClick then
        show = false
    end

    if show then
        local firstSid, isShow
        for k, v in ipairs(positionList) do
            local sid = v.sid
            local webData = gModelActivity:GetWebActivityDataById(sid)
            if webData then
                local config = webData.config
                local annieTips = config.annieTips or 0
                isShow = annieTips == 1
                if isShow then
                    self._annieDreamSecretSid = sid
                    break
                end
            else
                firstSid = sid
            end
        end

        if isShow ~= nil then
            self:ShowAnnieDreamSecretTipsBubble(isShow)
        elseif firstSid then
            gModelActivity:ReqActivityConfigData(firstSid)
        end
    else
        self:ShowAnnieDreamSecretTipsBubble(false)
    end
end

function LCityMap:OnSimulateAdmireChange()
    if not self._simuAdmireTran then
        self._simuAdmireTran = CS.FindTrans(self._mapTrans, "LayerRoot/BuildingLayer/Layer1/exhibition/champion")
        self._simuNormal = CS.FindTrans(self._mapTrans, "LayerRoot/BackLayer/Layer2/building6")
        self._simuSpecial = CS.FindTrans(self._mapTrans, "LayerRoot/BackLayer/Layer2/building7")
        self._simuName = CS.FindTrans(self._simuAdmireTran, "namebg/name")
    end

    --self:ShowAdmireName("测试")

    local canAdmire = gModelSimuFight:CanAdmire()
    CS.ShowObject(self._simuAdmireTran, canAdmire)
    CS.ShowObject(self._simuNormal, not canAdmire)
    CS.ShowObject(self._simuSpecial, canAdmire)

    if canAdmire then
        local playerInfo = gModelSimuFight:GetTopPlayer()
        if not playerInfo then return end

        local figure = playerInfo.figure
        if not self._topFigureRecord then
            self._topFigureRecord = {}
        end

        local str = string.replace(ccClientText(25320), playerInfo.name, playerInfo.serverName)
        self:ShowAdmireName(str)

        local spine = self._topFigureRecord[figure]
        if not spine then
            for k, v in pairs(self._topFigureRecord) do
                v:Destroy()
            end
            self._topFigureRecord = {}

            local ref = gModelPlayer:GetRoleAdventureImage(figure)
            if ref then
                spine = LDisplaySpine:New()
                local spineName = ref.spine
                local trans = CS.FindTrans(self._simuAdmireTran, "spine")
                spine:CreateSpine(trans, spineName)
                spine:StartLoad()
                self._topFigureRecord[figure] = spine
            end
        end
    end
end

function LCityMap:ClearTopFigure()
    if not self._topFigureRecord then return end

    for k, v in pairs(self._topFigureRecord) do
        v:Destroy()
    end
    self._topFigureRecord = {}

end

