function LCityMap:ShowMapAllUI(isShow)
    local needCheckSpriteNameList = self._needCheckSpriteNameList
    if not needCheckSpriteNameList then
        needCheckSpriteNameList = {
            "build_name_", -- 建筑名
            "redpoint", --红点
        }
    end

    local needCheckGoNameList = self._needCheckGoNameList
    if not needCheckGoNameList then
        needCheckGoNameList = {
            "bubble", -- 建筑名
            "adcard", --广告牌
        }
    end

    local alpha = isShow and 1 or 0
    local layerRoot = CS.FindTrans(self._mapTrans, "LayerRoot")
    local childs = layerRoot:GetComponentsInChildren(typeSpriteRenderer, true)
    for i = 0, childs.Length - 1 do
        local sp = childs[i]
        if CS.IsValidObject(sp) and sp.sprite then
            local spName = sp.sprite.name
            if not string.isempty(spName) then
                for k, v in ipairs(needCheckSpriteNameList) do
                    if string.find(spName, v) then
                        sp.color = Color.New(1, 1, 1, alpha)
                    end
                end
            end
        end
    end

    local transChilds = layerRoot:GetComponentsInChildren(typeTransform, true)
    for i = 0, transChilds.Length - 1 do
        local ts = transChilds[i]
        if CS.IsValidObject(ts) then
            local goName = ts.gameObject.name
            if not string.isempty(goName) then
                for k, v in ipairs(needCheckGoNameList) do
                    goName = string.lower(goName)
                    if string.find(goName, v) then
                        CS.ShowObject(ts, isShow)
                    end
                end
            end
        end
    end
end

