function LCityMap:SetMapSkin(cfg)
    if not cfg then return end

    local tran = CS.FindTrans(self._mapTrans, "LayerRoot/BackLayer/Layer0/bg2")
    self:SetSprite(tran, cfg.showIcon)
    tran = CS.FindTrans(self._mapTrans, "LayerRoot/EffectLayer/LayerFront")
    if not string.isempty(cfg.effect) then
        self.mapEff = LDisplayEffect:New()
        self.mapEff:CreateEffect(tran, cfg.effect)
        self.mapEff:SetLoadedFunction(function()
            self.mapEff:SetEffectScale(1)
            local dpParentTrans = self.mapEff:GetParentTrans()
            local rendererSort = dpParentTrans:GetComponent(typeof(CS.YXUISorting))
            if rendererSort then
                rendererSort:SetLayerName(LGameUI.UI_SORTLAYER_UITOUCH)
            end
        end)
        self.mapEff:StartLoadEffect()
    end
end

function LCityMap:ShowBubbleTran(b)
    if self._buildingLocks then
        for _, v in pairs(self._buildingLocks) do
            CS.ShowObject(v._bubbleTran, b)
        end
    end
end
